query PlaybackAccessToken($login: String!, $isLive: Boolean!, $vodID: ID!, $isVod: Boolean!, $playerType: String!, $platform: String!) {
  streamPlaybackAccessToken(
    channelName: $login
    params: {platform: $platform, playerBackend: "mediaplayer", playerType: $playerType}
  ) @include(if: $isLive) {
    value
    signature
    authorization {
      isForbidden
      forbiddenReasonCode
    }
  }
  videoPlaybackAccessToken(
    id: $vodID
    params: {platform: $platform, playerBackend: "mediaplayer", playerType: $playerType}
  ) @include(if: $isVod) {
    value
    signature
  }
}
